// generar_210_test_rapido.js
// CHIQUI Entre Señales — Nuevo tipo de examen "🧪 Test rápido"
//
// Qué hace este script:
// 1) components/ExamenesLab.tsx → nuevo tipo "Test rápido" con catálogo
//    desacoplado por especie (Gato: FelV, FIV, Coronavirus Felino;
//    Perro: Ehrlichia, Anaplasma, Dirofilaria, Leishmania, Lyme, 4DX
//    IDEXX), selección múltiple, resultado Negativo/Positivo/
//    Indeterminado por test, observación opcional por test, "+ agregar
//    otro test" para tests fuera del catálogo, historial con resumen
//    compacto (⚠️ N positivos) y comparación de evolución entre fechas.
// 2) components/ExamenesLabVet.tsx → los test rápidos aparecen en /vet:
//    por defecto solo el más reciente, positivos destacados en rojo con
//    ⚠️, "✅ Sin resultados positivos" si todo negativo, y comparación
//    entre fechas por evolución de resultados (no por rangos).
//
// Para agregar un test nuevo en el futuro: solo sumar una línea al
// CATALOGO_TESTS_RAPIDOS en ExamenesLab.tsx. No se necesita pantalla
// nueva ni tipo de examen nuevo.
//
// IMPORTANTE: antes de correr este script, ejecuta el SQL
// sql_210_test_rapido.sql en Supabase (New snippet), porque la columna
// "observacion" debe existir antes de que la app intente guardarla.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_210_test_rapido.js

const fs = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ExamenesLab.tsx",
    base64: ""
  },
  {
    ruta: "components/ExamenesLabVet.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 2 archivos escritos correctamente.')
  console.log('Recuerda: primero el SQL en Supabase, luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
